/**
 * @fileType test
 * @domain frontend
 * @pattern pdf-media, error-handling, react-testing
 * @ai-summary Unit tests for PDFMedia component error handling and retry functionality
 */
import { describe, expect, it, vi } from 'vitest'
import { render, screen, fireEvent, waitFor } from '@testing-library/react'
import '@testing-library/jest-dom'

// Mock dependencies before importing PDFMedia
vi.mock('@/infra/system-events', () => ({
  systemEventBus: {
    emit: vi.fn(),
  },
  SYSTEM_EVENTS: {
    PDF_VIEWED: 'pdf-viewed',
  },
}))

vi.mock('@/infra/utils/ui', () => ({
  cn: (...classes: (string | undefined | null | false)[]) => classes.filter(Boolean).join(' '),
}))

// Now import the component after mocks are set up
import { PDFMedia } from '@/ui/web/media/PDFMedia'

// Type for resource prop
type MediaResource = {
  filename: string
  url?: string
  pageCount?: number
}

describe('PDFMedia Component', () => {
  const defaultProps = {
    resource: {
      filename: 'test.pdf',
      url: '/api/media/file/test.pdf',
    } as MediaResource,
  }

  beforeEach(() => {
    vi.clearAllMocks()
  })

  describe('Error handling and retry', () => {
    it('should render retry button when iframe fails to load', async () => {
      const { container } = render(<PDFMedia {...defaultProps} />)

      // Get the iframe
      const iframe = container.querySelector('iframe')
      expect(iframe).toBeInTheDocument()

      // Simulate error event on iframe
      fireEvent.error(iframe!)

      // Should show a retry button
      await waitFor(() => {
        const retryButton = screen.getByRole('button', { name: /retry|נסה שוב/i })
        expect(retryButton).toBeInTheDocument()
      })
    })

    it('should append cache-busting parameter when retry is clicked', async () => {
      const { container } = render(<PDFMedia {...defaultProps} />)

      const iframe = container.querySelector('iframe')
      expect(iframe).toBeInTheDocument()

      // Simulate error
      fireEvent.error(iframe!)

      // Click retry
      await waitFor(() => {
        const retryButton = screen.getByRole('button', { name: /retry|נסה שוב/i })
        fireEvent.click(retryButton)
      })

      // Check that iframe src now contains cache-busting parameter
      const updatedIframe = container.querySelector('iframe')
      expect(updatedIframe).toHaveAttribute('src', expect.stringMatching(/&t=/))
    })

    it('should limit retries to maximum of 3 attempts', async () => {
      const { container } = render(<PDFMedia {...defaultProps} />)

      const iframe = container.querySelector('iframe')
      expect(iframe).toBeInTheDocument()

      // First error and retry
      fireEvent.error(iframe!)
      await waitFor(() => {
        const retryButton = screen.getByRole('button', { name: /retry|נסה שוב/i })
        fireEvent.click(retryButton)
      })

      // Second error and retry
      fireEvent.error(iframe!)
      await waitFor(() => {
        const retryButton = screen.getByRole('button', { name: /retry|נסה שוב/i })
        fireEvent.click(retryButton)
      })

      // Third error and retry - this should exhaust retries
      fireEvent.error(iframe!)
      await waitFor(() => {
        const retryButton = screen.queryByRole('button', { name: /retry|נסה שוב/i })
        // After 3 retries, should NOT show retry button anymore
        expect(retryButton).not.toBeInTheDocument()
      })
    })

    it('should show permanent error message after max retries exhausted', async () => {
      const { container } = render(<PDFMedia {...defaultProps} />)

      const iframe = container.querySelector('iframe')
      expect(iframe).toBeInTheDocument()

      // Exhaust all retries
      for (let i = 0; i < 3; i++) {
        fireEvent.error(iframe!)
        await waitFor(() => {
          const retryButton = screen.getByRole('button', { name: /retry|נסה שוב/i })
          fireEvent.click(retryButton)
        })
      }

      // Should show error message instead of retry button
      await waitFor(() => {
        const errorMessage = screen.getByText(/error|שגיאה|failed to load/i)
        expect(errorMessage).toBeInTheDocument()
      })
    })
  })

  describe('Normal loading', () => {
    it('should render iframe with correct src when no error occurs', () => {
      const { container } = render(<PDFMedia {...defaultProps} />)

      const iframe = container.querySelector('iframe')
      expect(iframe).toBeInTheDocument()
      expect(iframe).toHaveAttribute('src', expect.stringContaining('/api/pdfjs-viewer'))
      expect(iframe).toHaveAttribute('src', expect.stringContaining('test.pdf'))
    })

    it('should not show error state when PDF loads successfully', () => {
      const { container } = render(<PDFMedia {...defaultProps} />)

      // No error state should be visible
      expect(screen.queryByRole('button', { name: /retry|נסה שוב/i })).not.toBeInTheDocument()
      expect(screen.queryByText(/error|שגיאה/i)).not.toBeInTheDocument()
    })
  })
})

