// @vitest-environment jsdom
import { PDFMedia } from '@/ui/web/media/PDFMedia'
import type { Media as MediaType } from '@/payload-types'
import { cleanup, render, screen, fireEvent, waitFor } from '@testing-library/react'
import { afterEach, describe, expect, it, vi } from 'vitest'

// Mock dependencies
vi.mock('@/infra/system-events', () => ({
  systemEventBus: {
    emit: vi.fn(),
  },
  SYSTEM_EVENTS: {
    PDF_VIEWED: 'pdf-viewed',
  },
}))

vi.mock('@/infra/utils/ui', () => ({
  cn: vi.fn((...classes: string[]) => classes.filter(Boolean).join(' ')),
}))

describe('PDFMedia Component - Error Handling', () => {
  afterEach(() => {
    cleanup()
    vi.restoreAllMocks()
  })

  // Helper to create a valid Media resource
  const createMockMedia = (overrides?: Partial<MediaType>): MediaType => ({
    id: 'test-id',
    tenant: 'test-tenant',
    type: 'pdf',
    retentionPolicy: 'persistent',
    updatedAt: '2024-01-01T00:00:00.000Z',
    createdAt: '2024-01-01T00:00:00.000Z',
    filename: 'test.pdf',
    url: '/api/media/file/test.pdf',
    mimeType: 'application/pdf',
    ...overrides,
  })

  describe('Error handling and retry', () => {
    it('should render retry button when iframe fails to load', async () => {
      const mockMedia = createMockMedia()
      const { container } = render(<PDFMedia resource={mockMedia} />)

      // Get the iframe
      const iframe = container.querySelector('iframe')
      expect(iframe).toBeTruthy()

      // Simulate error event on iframe
      fireEvent.error(iframe!)

      // Should show a retry button
      await waitFor(() => {
        const retryButton = screen.getByRole('button', { name: /retry|נסה שוב/i })
        expect(retryButton).toBeTruthy()
      })
    })

    it('should append cache-busting parameter when retry is clicked', async () => {
      const mockMedia = createMockMedia()
      const { container } = render(<PDFMedia resource={mockMedia} />)

      const iframe = container.querySelector('iframe')
      expect(iframe).toBeTruthy()

      // Get initial src
      const initialSrc = iframe!.getAttribute('src')

      // Simulate error
      fireEvent.error(iframe!)

      // Click retry
      await waitFor(() => {
        const retryButton = screen.getByRole('button', { name: /retry|נסה שוב/i })
        fireEvent.click(retryButton)
      })

      // Check that iframe src now contains cache-busting parameter
      const updatedIframe = container.querySelector('iframe')
      const updatedSrc = updatedIframe?.getAttribute('src')
      expect(updatedSrc).toContain('&t=')
      expect(updatedSrc).not.toBe(initialSrc)
    })

    it('should limit retries to maximum of 3 attempts', async () => {
      const mockMedia = createMockMedia()
      const { container } = render(<PDFMedia resource={mockMedia} />)

      const iframe = container.querySelector('iframe')
      expect(iframe).toBeTruthy()

      // First error and retry
      fireEvent.error(iframe!)
      await waitFor(() => {
        const retryButton = screen.getByRole('button', { name: /retry|נסה שוב/i })
        fireEvent.click(retryButton)
      })

      // Second error and retry
      fireEvent.error(iframe!)
      await waitFor(() => {
        const retryButton = screen.getByRole('button', { name: /retry|נסה שוב/i })
        fireEvent.click(retryButton)
      })

      // Third error and retry - this should exhaust retries
      fireEvent.error(iframe!)
      await waitFor(() => {
        const retryButton = screen.queryByRole('button', { name: /retry|נסה שוב/i })
        // After 3 retries, should NOT show retry button anymore
        expect(retryButton).toBeFalsy()
      })
    })

    it('should show permanent error message after max retries exhausted', async () => {
      const mockMedia = createMockMedia()
      const { container } = render(<PDFMedia resource={mockMedia} />)

      const iframe = container.querySelector('iframe')
      expect(iframe).toBeTruthy()

      // Exhaust all retries
      for (let i = 0; i < 3; i++) {
        fireEvent.error(iframe!)
        await waitFor(() => {
          const retryButton = screen.getByRole('button', { name: /retry|נסה שוב/i })
          fireEvent.click(retryButton)
        })
      }

      // Should show error message instead of retry button
      await waitFor(() => {
        // Look for error-related text
        const errorElements = screen.getAllByText(/error|שגיאה|failed to load/i)
        expect(errorElements.length).toBeGreaterThan(0)
      })
    })
  })

  describe('Normal loading', () => {
    it('should render iframe with correct src when no error occurs', () => {
      const mockMedia = createMockMedia()
      const { container } = render(<PDFMedia resource={mockMedia} />)

      const iframe = container.querySelector('iframe')
      expect(iframe).toBeTruthy()
      expect(iframe?.getAttribute('src')).toContain('/api/pdfjs-viewer')
      expect(iframe?.getAttribute('src')).toContain('test.pdf')
    })

    it('should not show error state when PDF loads successfully', () => {
      const mockMedia = createMockMedia()
      render(<PDFMedia resource={mockMedia} />)

      // No error state should be visible
      expect(screen.queryByRole('button', { name: /retry|נסה שוב/i })).toBeFalsy()
      expect(screen.queryByText(/error|שגיאה/i)).toBeFalsy()
    })
  })
})

