/**
 * @fileType test
 * @domain backend
 * @pattern pdf-viewer, api-route, observability
 * @ai-summary Unit tests for PDF.js viewer API route X-PDF-Source header functionality
 */
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest'
import { NextRequest } from 'next/server'

// Mock the modules before importing
vi.mock('@/infra/pdfjs/config', () => ({
  RESPONSE_HEADERS: {
    'Content-Type': 'text/html; charset=utf-8',
    'Cache-Control': 'public, max-age=3600',
    'Access-Control-Allow-Origin': '*',
    'X-Content-Type-Options': 'nosniff',
    'Content-Disposition': 'inline',
  },
  CDN_BASE: 'https://example.blob.vercel-storage.com/pdfjs/4.4.168',
  VIEWER_URLS: {
    html: 'https://example.blob.vercel-storage.com/pdfjs/4.4.168/viewer-I6DnqEMX9W9cwNNvWKm3D8YvXdCzUA.html',
    mjs: 'https://example.blob.vercel-storage.com/pdfjs/4.4.168/viewer-SyYgQ0jufpmBIqrWX2zGA21kZmurH6.mjs',
    css: 'https://example.blob.vercel-storage.com/pdfjs/4.4.168/viewer-MgMiA2nNdPgVwb4uc8CAB6Twx6vmUC.css',
    pdfMjs: 'https://example.blob.vercel-storage.com/pdfjs/4.4.168/build/pdf.mjs',
    pdfWorkerMjs: 'https://example.blob.vercel-storage.com/pdfjs/4.4.168/build/pdf.worker.mjs',
  },
}))

vi.mock('@/infra/pdfjs/renderer', () => ({
  renderViewerHtml: vi.fn().mockResolvedValue('<html><head></head><body></body></html>'),
  rewriteCss: vi.fn().mockReturnValue('.test { color: red; }'),
  validateRewrittenHtml: vi.fn().mockResolvedValue({ valid: true, issues: [] }),
}))

vi.mock('@/infra/pdfjs/template-loader', () => ({
  loadViewerTemplate: vi.fn().mockResolvedValue({
    ok: true,
    html: '<html><head></head><body></body></html>',
  }),
  loadViewerCss: vi.fn().mockResolvedValue({
    ok: true,
    css: '.test { color: red; }',
  }),
  clearTemplateCache: vi.fn(),
}))

vi.mock('@/infra/pdfjs/validator', () => ({
  validateFileUrl: vi.fn(),
  redactUrl: vi.fn((url: string) => url),
}))

vi.mock('@/infra/blob/vercel-blob-adapter', () => ({
  isVercelBlobUrl: vi.fn(),
}))

vi.mock('@/infra/utils/logger', () => ({
  logger: {
    child: vi.fn().mockReturnValue({
      debug: vi.fn(),
      info: vi.fn(),
      warn: vi.fn(),
      error: vi.fn(),
    }),
    debug: vi.fn(),
    info: vi.fn(),
    warn: vi.fn(),
    error: vi.fn(),
  },
}))

// Import after mocks are set up
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const MockGET = (await import('@/app/api/pdfjs-viewer/route')).GET

describe('PDF.js Viewer API Route', () => {
  beforeEach(() => {
    vi.clearAllMocks()
  })

  describe('X-PDF-Source header', () => {
    it('should add X-PDF-Source header with value "blob" for Vercel Blob URLs', async () => {
      // Setup mocks
      const mockValidateResult = {
        valid: true,
        url: 'https://96hg0ck1hvrndmxp.public.blob.vercel-storage.com/media/test.pdf',
      }
      vi.mocked(vi.mocked(await import('@/infra/pdfjs/validator')).validateFileUrl).mockReturnValue(mockValidateResult as any)
      vi.mocked(vi.mocked(await import('@/infra/blob/vercel-blob-adapter')).isVercelBlobUrl).mockReturnValue(true)

      // Create request with Vercel Blob URL
      const url = new URL('http://localhost/api/pdfjs-viewer')
      url.searchParams.set('file', 'https://96hg0ck1hvrndmxp.public.blob.vercel-storage.com/media/test.pdf')
      const request = new NextRequest(url)

      // Call the handler
      const response = await MockGET(request)

      // Assert
      expect(response.status).toBe(200)
      expect(response.headers.get('X-PDF-Source')).toBe('blob')
    })

    it('should add X-PDF-Source header with value "proxy" for relative URLs', async () => {
      // Setup mocks
      const mockValidateResult = {
        valid: true,
        url: 'http://localhost/api/media/file/test.pdf',
      }
      vi.mocked(vi.mocked(await import('@/infra/pdfjs/validator')).validateFileUrl).mockReturnValue(mockValidateResult as any)
      vi.mocked(vi.mocked(await import('@/infra/blob/vercel-blob-adapter')).isVercelBlobUrl).mockReturnValue(false)

      // Create request with relative URL
      const url = new URL('http://localhost/api/pdfjs-viewer')
      url.searchParams.set('file', '/api/media/file/test.pdf')
      const request = new NextRequest(url)

      // Call the handler
      const response = await MockGET(request)

      // Assert
      expect(response.status).toBe(200)
      expect(response.headers.get('X-PDF-Source')).toBe('proxy')
    })
  })

  describe('Request validation', () => {
    it('should return 400 when file parameter is missing', async () => {
      vi.mocked(vi.mocked(await import('@/infra/pdfjs/validator')).validateFileUrl).mockReturnValue({
        valid: false,
        error: { type: 'missing', message: 'Missing file parameter' },
      })

      const url = new URL('http://localhost/api/pdfjs-viewer')
      const request = new NextRequest(url)

      const response = await MockGET(request)

      expect(response.status).toBe(400)
      const body = await response.json()
      expect(body.error).toBe('Invalid file URL')
    })
  })
})
